import xml.etree.ElementTree as ET
from django.contrib.auth import login, authenticate
from django.shortcuts import redirect
from django.http import HttpResponse

def saml_login(request):
    if request.method == 'POST':
        xml_data = request.body
        root = ET.fromstring(xml_data)

        name_id = None
        attributes = {}
        
        for child in root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attribute_name = child.get('Name')
            if attribute_name == 'NameID':
                name_id = child.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            else:
                value_tag = child.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')
                if value_tag is not None:
                    attributes[attribute_name] = value_tag.text

        if name_id and attributes:
            user, created = User.objects.get_or_create(username=name_id)
            for attr_key, attr_value in attributes.items():
                setattr(user, attr_key, attr_value)
            user.save()
            
            authenticate(request, username=name_id)
            request.session['user_info'] = {
                'username': name_id,
                'attributes': attributes
            }
            return redirect('dashboard')
        else:
            return HttpResponse("Invalid SAML response", status=400)
    return HttpResponse("Unsupported HTTP method", status=405)

